total_percent = 0.0
total_allocated_amount = 0.0
total_billed = 0.0

for milestone in doc.get("custom_project_milestones", []):
    if not milestone.planned_date:
        frappe.throw(f"Planned Date is mandatory for milestone '{milestone.milestone_name}'")
    total_percent += frappe.utils.flt(milestone.percentage)
    total_allocated_amount += frappe.utils.flt(milestone.amount)
    if milestone.status == "Invoiced":
        total_billed += frappe.utils.flt(milestone.amount)

if total_percent > 100:
    frappe.throw("Total milestones percentage cannot exceed 100%. Currently at " + str(total_percent) + "%")

if frappe.utils.flt(doc.custom_total_contract_value) > 0 and total_allocated_amount > frappe.utils.flt(doc.custom_total_contract_value):
    frappe.throw("Milestones total amount (" + str(total_allocated_amount) + ") cannot exceed Total Contract Value (" + str(doc.custom_total_contract_value) + ")")

if total_percent < 100 and len(doc.get("custom_project_milestones", [])) > 0:
    frappe.msgprint("Warning: Milestones only cover " + str(total_percent) + "% of the contract. Add more milestones to cover the full 100%.", indicator="orange", alert=1)

doc.total_billed_amount = total_billed
